package il.co.dcd.composermapper.render; import il.co.dcd.composermapper.model.TagNode;
public final class MarkdownSupport { private MarkdownSupport(){} public static String bullet(String v){ return "- "+v+System.lineSeparator(); } public static String code(String v){ return "`"+v+"`"; } public static String tagTree(TagNode n,int level){ if(n==null) return ""; String indent="  ".repeat(Math.max(0,level)); StringBuilder sb=new StringBuilder(); sb.append(indent).append("<").append(n.getTagName()); n.getAttributes().forEach((k,v)->sb.append(" ").append(k).append("=\"").append(v).append("\"")); if(n.getChildren().isEmpty()){ sb.append("/>\n"); return sb.toString(); } sb.append(">\n"); for(TagNode c:n.getChildren()) sb.append(tagTree(c,level+1)); sb.append(indent).append("</").append(n.getTagName()).append(">\n"); return sb.toString(); } }
